var data = $input.first().json;
var staticData = $getWorkflowStaticData('node');
var now = Date.now();
var COOLDOWN = 5 * 60 * 1000;
var N8N_URL = 'https://n8n.oovoom.com';

var isExecError = Boolean(data.execution);
var workflowName = data.workflow ? data.workflow.name : 'Unknown';
var workflowId = data.workflow ? data.workflow.id : '';
var errorMsg, nodeName, execUrl, mode;

if (isExecError) {
  errorMsg = data.execution.error ? data.execution.error.message : 'Unknown error';
  nodeName = data.execution.lastNodeExecuted || '';
  execUrl = data.execution.url || '';
  mode = data.execution.mode || '';
} else {
  errorMsg = data.trigger && data.trigger.error ? data.trigger.error.message : 'Unknown';
  var cause = data.trigger && data.trigger.error && data.trigger.error.cause
    ? data.trigger.error.cause.message : '';
  if (cause) errorMsg = errorMsg + '\nCause: ' + cause;
  nodeName = '';
  execUrl = '';
  mode = data.trigger ? data.trigger.mode : '';
}

var dedupKey = workflowId + '_' + errorMsg.slice(0, 100);
var keys = Object.keys(staticData);
for (var i = 0; i < keys.length; i++) {
  if (typeof staticData[keys[i]] === 'number' && staticData[keys[i]] < now - COOLDOWN) {
    delete staticData[keys[i]];
  }
}
if (staticData[dedupKey] && (now - staticData[dedupKey]) < COOLDOWN) {
  return [];
}
staticData[dedupKey] = now;

var timestamp = new Date().toISOString().replace('T', ' ').slice(0, 19);
var blocks = [];

blocks.push({
  type: 'header',
  text: { type: 'plain_text', text: isExecError ? '\ud83d\udd34 Workflow Failed' : '\ud83d\udd34 Trigger Failed' }
});

var fields = [
  { type: 'mrkdwn', text: '*Workflow:*\n' + workflowName }
];
if (nodeName) fields.push({ type: 'mrkdwn', text: '*Node:*\n' + nodeName });
if (mode) fields.push({ type: 'mrkdwn', text: '*Mode:*\n' + mode });
fields.push({ type: 'mrkdwn', text: '*Time:*\n' + timestamp });
blocks.push({ type: 'section', fields: fields });

blocks.push({
  type: 'section',
  text: { type: 'mrkdwn', text: '*Error:*\n```' + errorMsg.slice(0, 500) + '```' }
});

var buttons = [];
if (execUrl) {
  buttons.push({
    type: 'button',
    text: { type: 'plain_text', text: '\ud83d\udd17 View Execution' },
    url: execUrl,
    style: 'danger'
  });
}
buttons.push({
  type: 'button',
  text: { type: 'plain_text', text: '\u2699\ufe0f Open Workflow' },
  url: N8N_URL + '/workflow/' + workflowId
});
blocks.push({ type: 'actions', elements: buttons });
blocks.push({ type: 'divider' });

var fallback = (isExecError ? 'Failed' : 'Trigger Failed') + ': ' + workflowName + ' - ' + errorMsg.slice(0, 200);

return [{ json: { blocks: JSON.stringify(blocks), fallbackText: fallback } }];

var thisWorkflowId = $('Auto-Register Schedule').first().json;
var workflows = $input.all().map(function(i) { return i.json; });
var results = [];

for (var i = 0; i < workflows.length; i++) {
  var wf = workflows[i];
  if (!wf.active) continue;
  var settings = wf.settings || {};
  var needsUpdate = !settings.errorWorkflow || settings.saveDataErrorExecution !== 'all';
  if (needsUpdate) {
    results.push({ json: {
      workflowId: wf.id,
      name: wf.name,
      currentSettings: settings
    }});
  }
}

return results.length > 0 ? results : [];

